import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const mockCaptureFocusTarget = vi
    .fn()
    .mockReturnValue({ kind: "frontmost", identifier: "Terminal" });
const mockApplyFocusTarget = vi.fn();
const mockOpenOrNavigate = vi
    .fn()
    .mockResolvedValue({ sessionId: "test-session-id", opened: true });
const mockSetApiKey = vi.fn();
const mockIsPersistent = vi.fn().mockReturnValue(false);
const mockDestroy = vi.fn();
const mockSubscribeAbort = vi.fn();
const mockSubscribeDone = new Promise(() => { });
const mockSubscribe = vi
    .fn()
    .mockImplementation((_sessionId, onEvent) => {
    setTimeout(() => {
        onEvent({
            type: "studio:authenticated",
            data: { token: "login-api-key" },
        });
    }, 0);
    return { abort: mockSubscribeAbort, done: mockSubscribeDone };
});
const mockChannelClose = vi.fn().mockResolvedValue(undefined);
const mockChannel = {
    openOrNavigate: mockOpenOrNavigate,
    subscribe: mockSubscribe,
    close: mockChannelClose,
    setApiKey: mockSetApiKey,
    isPersistent: mockIsPersistent,
    destroy: mockDestroy,
};
vi.mock("../browser.js", () => ({
    openChromelessWindow: vi.fn().mockReturnValue(1234),
}));
let mockApiKey = null;
let mockHasCredentials = false;
const mockSaveCredentials = vi.fn();
vi.mock("../config.js", () => ({
    getConfig: () => ({
        serviceUrl: "http://localhost:3000",
        apiKey: mockApiKey,
    }),
    hasCredentials: () => mockHasCredentials,
    saveCredentials: (...args) => mockSaveCredentials(...args),
}));
vi.mock("../frontmostApp.js", () => ({
    captureFocusTarget: (...args) => mockCaptureFocusTarget(...args),
    applyFocusTarget: (...args) => mockApplyFocusTarget(...args),
}));
vi.mock("../agentSessionKey.js", () => ({
    resolveAgentSessionKey: () => "test-key",
}));
const mockTailStudioEvents = vi
    .fn()
    .mockReturnValue(new Promise(() => { }));
vi.mock("../studioEventLog.js", () => ({
    appendStudioEvent: vi.fn(),
    studioEventToLogLine: (event) => ({
        event: event.type.replace("studio:", ""),
    }),
    eventLogPathForKey: (key) => `/tmp/${key}.events.jsonl`,
    readStudioEventLogTail: () => ({ lines: [], nextLine: 1 }),
    tailStudioEvents: (...args) => mockTailStudioEvents(...args),
}));
const mockTryClaimStudioMonitor = vi.fn().mockReturnValue(true);
const mockReleaseStudioMonitor = vi.fn();
const mockUpdateActiveStudioSession = vi.fn();
vi.mock("../activeStudioSession.js", () => ({
    writeActiveStudioSession: vi.fn(),
    clearActiveStudioSession: vi.fn(),
    updateActiveStudioSession: (...args) => mockUpdateActiveStudioSession(...args),
    tryClaimStudioMonitor: (...args) => mockTryClaimStudioMonitor(...args),
    releaseStudioMonitor: (...args) => mockReleaseStudioMonitor(...args),
}));
const mockResolveChannel = vi.fn().mockResolvedValue(mockChannel);
vi.mock("../studioChannel.js", () => ({
    resolveChannel: (...args) => mockResolveChannel(...args),
}));
import { openStudioTo } from "./openStudioTo.js";
function extractRedirectUrl(initialPath) {
    const url = new URL(`http://x${initialPath}`);
    return url.searchParams.get("redirect_url") ?? "";
}
function extractSessionFromPath(initialPath) {
    const url = new URL(`http://x${initialPath}`);
    return url.searchParams.get("session") ?? "";
}
describe("openStudioTo", () => {
    beforeEach(() => {
        vi.clearAllMocks();
        mockTryClaimStudioMonitor.mockReturnValue(true);
        mockTailStudioEvents.mockReturnValue(new Promise(() => { }));
        mockApiKey = null;
        mockHasCredentials = false;
        mockOpenOrNavigate.mockResolvedValue({
            sessionId: "test-session-id",
            opened: true,
        });
        mockResolveChannel.mockResolvedValue(mockChannel);
        mockSubscribe.mockImplementation((_sessionId, onEvent) => {
            setTimeout(() => {
                onEvent({
                    type: "studio:authenticated",
                    data: { token: "login-api-key" },
                });
            }, 0);
            return { abort: mockSubscribeAbort, done: mockSubscribeDone };
        });
    });
    describe("resolveChannel is always called", () => {
        it("calls resolveChannel on the login path", async () => {
            await openStudioTo("/studio", { forceLogin: true });
            expect(mockResolveChannel).toHaveBeenCalledOnce();
            expect(mockResolveChannel).toHaveBeenCalledWith("", "http://localhost:3000");
        });
        it("marks the pointer authenticated after login so it is not reused", async () => {
            await openStudioTo("/studio", { forceLogin: true });
            expect(mockUpdateActiveStudioSession).toHaveBeenCalledWith({
                authenticated: true,
            });
        });
        it("reports opened:false when login reused an existing window", async () => {
            mockOpenOrNavigate.mockResolvedValueOnce({
                sessionId: "reused-session",
                opened: false,
            });
            const result = await openStudioTo("/studio", { forceLogin: true });
            // The channel reused a live window, so login must not claim it opened one.
            expect(result.opened).toBe(false);
            expect(result.sessionId).toBe("reused-session");
        });
        it("calls resolveChannel on the authenticated path", async () => {
            mockApiKey = "real-key";
            mockHasCredentials = true;
            await openStudioTo("/studio/traces");
            expect(mockResolveChannel).toHaveBeenCalledOnce();
            expect(mockResolveChannel).toHaveBeenCalledWith("real-key", "http://localhost:3000");
        });
        it("calls resolveChannel with forceLogin even if credentials exist", async () => {
            mockApiKey = "real-key";
            mockHasCredentials = true;
            await openStudioTo("/studio", { forceLogin: true });
            expect(mockResolveChannel).toHaveBeenCalledOnce();
            expect(mockResolveChannel).toHaveBeenCalledWith("", "http://localhost:3000");
        });
    });
    describe("channel.openOrNavigate is always called", () => {
        it("calls openOrNavigate on the login path (to sign-in page)", async () => {
            await openStudioTo("/studio", { forceLogin: true });
            expect(mockOpenOrNavigate).toHaveBeenCalled();
            const firstCallPath = mockOpenOrNavigate.mock.calls[0][0];
            expect(firstCallPath).toContain("/studio/sign-in");
        });
        it("calls openOrNavigate on the authenticated path (to target page)", async () => {
            mockApiKey = "real-key";
            mockHasCredentials = true;
            await openStudioTo("/studio/traces");
            expect(mockOpenOrNavigate).toHaveBeenCalledOnce();
            expect(mockOpenOrNavigate.mock.calls[0][0]).toBe("/studio/traces");
        });
        it("calls openOrNavigate once on login (sign-in only, redirect handles destination)", async () => {
            await openStudioTo("/studio/traces", { forceLogin: true });
            expect(mockOpenOrNavigate).toHaveBeenCalledTimes(1);
            expect(mockOpenOrNavigate.mock.calls[0][0]).toContain("/studio/sign-in");
        });
    });
    describe("login path", () => {
        it("uses freshWindowPath as the post-login redirect when provided", async () => {
            await openStudioTo("/studio", {
                forceLogin: true,
                freshWindowPath: "/studio/close?autoClose=true&message=Login%20complete",
            });
            const initialPath = mockOpenOrNavigate.mock.calls[0][0];
            const redirectUrl = extractRedirectUrl(initialPath);
            expect(redirectUrl).toContain("/studio/close");
            expect(redirectUrl).toContain("autoClose=true");
            expect(redirectUrl).toContain("pluginLogin=true");
            expect(redirectUrl).toContain("session=");
            expect(redirectUrl).not.toMatch(/^\/studio\?/);
        });
        it("uses path as the post-login redirect when freshWindowPath is not provided", async () => {
            await openStudioTo("/studio/traces", {
                forceLogin: true,
            });
            const initialPath = mockOpenOrNavigate.mock.calls[0][0];
            const redirectUrl = extractRedirectUrl(initialPath);
            expect(redirectUrl).toContain("/studio/traces");
            expect(redirectUrl).toContain("pluginLogin=true");
            expect(redirectUrl).toContain("session=");
            expect(redirectUrl).not.toContain("/studio/close");
        });
        it("appends session and pluginLogin with & when freshWindowPath has query params", async () => {
            await openStudioTo("/studio", {
                forceLogin: true,
                freshWindowPath: "/studio/close?autoClose=true",
            });
            const initialPath = mockOpenOrNavigate.mock.calls[0][0];
            const redirectUrl = extractRedirectUrl(initialPath);
            expect(redirectUrl).toMatch(/\/studio\/close\?autoClose=true&session=.+&pluginLogin=true/);
        });
        it("uses ? separator when freshWindowPath has no query params", async () => {
            await openStudioTo("/studio", {
                forceLogin: true,
                freshWindowPath: "/studio/close",
            });
            const initialPath = mockOpenOrNavigate.mock.calls[0][0];
            const redirectUrl = extractRedirectUrl(initialPath);
            expect(redirectUrl).toMatch(/\/studio\/close\?session=.+&pluginLogin=true/);
        });
        it("passes sessionId to channel.openOrNavigate", async () => {
            await openStudioTo("/studio", {
                forceLogin: true,
                freshWindowPath: "/studio/close",
            });
            const opts = mockOpenOrNavigate.mock.calls[0][1];
            expect(opts.sessionId).toBeDefined();
            expect(typeof opts.sessionId).toBe("string");
        });
        it("bakes the same sessionId into the sign-in URL and openOrNavigate opts", async () => {
            await openStudioTo("/studio", { forceLogin: true });
            const initialPath = mockOpenOrNavigate.mock.calls[0][0];
            const opts = mockOpenOrNavigate.mock.calls[0][1];
            const sessionInUrl = extractSessionFromPath(initialPath);
            expect(sessionInUrl).toBe(opts.sessionId);
        });
        it("calls setApiKey after login", async () => {
            await openStudioTo("/studio", {
                forceLogin: true,
                freshWindowPath: "/studio/close",
            });
            expect(mockSetApiKey).toHaveBeenCalledWith("login-api-key");
        });
        it("saves credentials after login", async () => {
            await openStudioTo("/studio", { forceLogin: true });
            expect(mockSaveCredentials).toHaveBeenCalledWith("login-api-key");
        });
        it("fires onLoginRequired with the sessionId and full sign-in URL", async () => {
            const onLoginRequired = vi.fn();
            await openStudioTo("/studio", { forceLogin: true, onLoginRequired });
            expect(onLoginRequired).toHaveBeenCalledOnce();
            const [sessionId, signInUrl] = onLoginRequired.mock.calls[0];
            expect(typeof sessionId).toBe("string");
            expect(signInUrl).toContain("http://localhost:3000/studio/sign-in");
            expect(signInUrl).toContain("redirect_url=");
        });
        it("fires onAuthenticated with the sessionId after login", async () => {
            const onAuthenticated = vi.fn();
            await openStudioTo("/studio", { forceLogin: true, onAuthenticated });
            expect(onAuthenticated).toHaveBeenCalledOnce();
            expect(typeof onAuthenticated.mock.calls[0][0]).toBe("string");
        });
        it("returns opened: true", async () => {
            const result = await openStudioTo("/studio", { forceLogin: true });
            expect(result.opened).toBe(true);
        });
        it("returns the login API key, not null", async () => {
            const result = await openStudioTo("/studio", { forceLogin: true });
            expect(result.apiKey).toBe("login-api-key");
        });
        it("rejects when subscribe onError fires", async () => {
            mockSubscribe.mockImplementation((_sessionId, _onEvent, onError) => {
                setTimeout(() => {
                    onError(new Error("connection lost"));
                }, 0);
                return { abort: mockSubscribeAbort, done: mockSubscribeDone };
            });
            await expect(openStudioTo("/studio", { forceLogin: true })).rejects.toThrow("connection lost");
        });
        it("rejects with login timeout when subscribe never fires", async () => {
            vi.useFakeTimers();
            try {
                mockSubscribe.mockImplementation(() => {
                    return { abort: mockSubscribeAbort, done: mockSubscribeDone };
                });
                const promise = openStudioTo("/studio", { forceLogin: true });
                // Attach rejection handler before advancing so it is not unhandled
                const rejection = expect(promise).rejects.toThrow("Login polling aborted");
                await vi.advanceTimersByTimeAsync(10 * 60 * 1000);
                await rejection;
            }
            finally {
                vi.useRealTimers();
            }
        });
        it("ignores studio:authenticated with non-string token", async () => {
            vi.useFakeTimers();
            try {
                mockSubscribe.mockImplementation((_sessionId, onEvent) => {
                    setTimeout(() => {
                        onEvent({
                            type: "studio:authenticated",
                            data: { token: 123 },
                        });
                    }, 0);
                    return { abort: mockSubscribeAbort, done: mockSubscribeDone };
                });
                const promise = openStudioTo("/studio", { forceLogin: true });
                // Advance past the queued onEvent (0ms) to deliver the non-string token
                await vi.advanceTimersByTimeAsync(1);
                // Attach rejection handler before advancing past LOGIN_TIMEOUT_MS
                const rejection = expect(promise).rejects.toThrow("Login polling aborted");
                // Advance past LOGIN_TIMEOUT_MS so the promise rejects rather than hanging
                await vi.advanceTimersByTimeAsync(10 * 60 * 1000);
                // The non-string token was ignored, so the promise rejects with the timeout
                await rejection;
            }
            finally {
                vi.useRealTimers();
            }
        });
        it("sets up event subscription after login when onEvent is provided", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio", { forceLogin: true, onEvent });
            expect(mockSubscribe).toHaveBeenCalledTimes(2);
        });
        it("restores focus and returns noop when no onEvent on login path", async () => {
            const result = await openStudioTo("/studio", { forceLogin: true });
            expect(result.abort).toBeTypeOf("function");
            await expect(result.done).resolves.toBeUndefined();
            expect(mockSubscribe).toHaveBeenCalledTimes(1);
            expect(mockApplyFocusTarget).toHaveBeenCalled();
        });
    });
    describe("authenticated path", () => {
        beforeEach(() => {
            mockApiKey = "real-key";
            mockHasCredentials = true;
        });
        it("does not call setApiKey", async () => {
            await openStudioTo("/studio/traces");
            expect(mockSetApiKey).not.toHaveBeenCalled();
        });
        it("does not subscribe for login on authenticated path", async () => {
            mockSubscribe.mockReturnValue({
                abort: mockSubscribeAbort,
                done: mockSubscribeDone,
            });
            await openStudioTo("/studio/traces");
        });
        it("does not call saveCredentials", async () => {
            await openStudioTo("/studio/traces");
            expect(mockSaveCredentials).not.toHaveBeenCalled();
        });
        it("passes clientHeaders through", async () => {
            const headers = { "x-test": "value" };
            await openStudioTo("/studio/traces", { clientHeaders: headers });
            const opts = mockOpenOrNavigate.mock.calls[0][1];
            expect(opts.clientHeaders).toEqual(headers);
        });
        it("returns the existing API key", async () => {
            const result = await openStudioTo("/studio/traces");
            expect(result.apiKey).toBe("real-key");
        });
        it("returns opened from channel response", async () => {
            mockOpenOrNavigate.mockResolvedValueOnce({
                sessionId: "s1",
                opened: false,
            });
            const result = await openStudioTo("/studio/traces");
            expect(result.opened).toBe(false);
        });
        it("subscribes to events when onEvent is provided", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            expect(mockSubscribe).toHaveBeenCalledOnce();
            expect(mockSubscribe.mock.calls[0][0]).toBe("test-session-id");
        });
        it("destroys channel when no onEvent is provided", async () => {
            const result = await openStudioTo("/studio/traces");
            result.abort();
            expect(mockDestroy).toHaveBeenCalledOnce();
        });
    });
    describe("no-daemon writer/reader election", () => {
        beforeEach(() => {
            mockApiKey = "real-key";
            mockHasCredentials = true;
        });
        it("writer (won the lock) polls via the channel", async () => {
            mockTryClaimStudioMonitor.mockReturnValue(true);
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            expect(mockTryClaimStudioMonitor).toHaveBeenCalled();
            expect(mockSubscribe).toHaveBeenCalledOnce();
            expect(mockTailStudioEvents).not.toHaveBeenCalled();
        });
        it("reader (lost the lock) tails the file instead of polling", async () => {
            mockTryClaimStudioMonitor.mockReturnValue(false);
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            expect(mockTailStudioEvents).toHaveBeenCalledOnce();
            expect(mockSubscribe).not.toHaveBeenCalled();
        });
        it("tail caller that loses the lock fire-and-forgets (writer keeps the file fresh)", async () => {
            mockTryClaimStudioMonitor.mockReturnValue(false);
            const result = await openStudioTo("/studio/traces", { tail: true });
            await expect(result.done).resolves.toBeUndefined();
            expect(mockTailStudioEvents).not.toHaveBeenCalled();
            expect(mockDestroy).toHaveBeenCalled();
        });
        it("tail caller that wins the lock becomes the writer", async () => {
            mockTryClaimStudioMonitor.mockReturnValue(true);
            await openStudioTo("/studio/traces", { tail: true });
            expect(mockSubscribe).toHaveBeenCalledOnce();
        });
    });
    describe("event subscription", () => {
        let capturedOnEvent;
        beforeEach(() => {
            vi.useFakeTimers();
            mockApiKey = "real-key";
            mockHasCredentials = true;
            mockSubscribe.mockImplementation((_sessionId, onEvent) => {
                capturedOnEvent = onEvent;
                return { abort: mockSubscribeAbort, done: mockSubscribeDone };
            });
        });
        afterEach(() => {
            vi.useRealTimers();
        });
        it("emits studio:session-ended after window-close grace period", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            expect(onEvent).not.toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(10_000);
            expect(onEvent).toHaveBeenCalledOnce();
            expect(onEvent.mock.calls[0][0]).toMatchObject({
                type: "studio:session-ended",
            });
        });
        it("cancels grace timer when studio:session-started fires during grace", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            capturedOnEvent({ type: "studio:window-closed", data: {} });
            await vi.advanceTimersByTimeAsync(5_000);
            capturedOnEvent({ type: "studio:session-started", data: {} });
            await vi.advanceTimersByTimeAsync(10_000);
            expect(onEvent).not.toHaveBeenCalled();
        });
        it("forwards studio:not-member and aborts subscription", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            capturedOnEvent({ type: "studio:not-member", data: {} });
            expect(onEvent).toHaveBeenCalledOnce();
            expect(onEvent.mock.calls[0][0]).toMatchObject({
                type: "studio:not-member",
            });
            expect(mockSubscribeAbort).toHaveBeenCalled();
        });
        it("forwards studio:return-to-agent and restores focus", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            capturedOnEvent({ type: "studio:return-to-agent", data: {} });
            expect(onEvent).toHaveBeenCalledOnce();
            expect(onEvent.mock.calls[0][0]).toMatchObject({
                type: "studio:return-to-agent",
            });
            expect(mockApplyFocusTarget).toHaveBeenCalled();
        });
        it("forwards studio:edit-with-agent and restores focus", async () => {
            const onEvent = vi.fn();
            await openStudioTo("/studio/traces", { onEvent });
            capturedOnEvent({
                type: "studio:edit-with-agent",
                data: { datasetId: "ds-1" },
            });
            expect(onEvent).toHaveBeenCalledOnce();
            expect(onEvent.mock.calls[0][0]).toMatchObject({
                type: "studio:edit-with-agent",
            });
            expect(mockApplyFocusTarget).toHaveBeenCalled();
        });
    });
});
